    for (t = 1; t <= 2; t++) {
      best = ""
      best_addr = 0
      for (i = 1; i <= count; i++) {
        if (addrs[i] <= targets[t]) {
          best_addr = addrs[i]
          best = names[i]
        }
      }
      printf "0x%x -> %s (at 0x%x, offset +0x%x)\n", targets[t], best, best_addr, targets[t]-best_addr
    }
  }
'

