arguments.command:
cd /tmp/sv-35ba5508e5dc46edb67c5d878195c5bf/symbols

# Get all FUNC symbols from the debug file's full symbol table, sorted by address
readelf -sW libmonosgen-2.0.so.debug | awk '
  $4 == "FUNC" && $2 ~ /^[0-9a-f]+$/ {
    addr = strtonum("0x" $2)
    if (addr > 0) {
      size = strtonum("0x" $3)
      name = $8
      # Skip thunks
      if (name !~ /^__CortexA53/ && name !~ /^\$/) {
        printf "%012x %6d %s\n", addr, size, name
      }
    }
  }
' | sort -n | awk '
  {
    addr = strtonum("0x" $1)
    size = $2 + 0
    name = $3
    addrs[++count] = addr
    sizes[count] = size
    names[count] = name
  }
  END {
    targets[1] = 0x2f4b20; targets[2] = 0x2f4c84
    for (t = 1; t <= 2; t++) {
      best = ""; best_addr = 0; best_size = 0
      for (i = 1; i <= count; i++) {
        if (addrs[i] <= targets[t]) {
          best_addr = addrs[i]
          best = names[i]
          best_size = sizes[i]
        }
      }
      end = (best_size > 0) ? best_addr + best_size : 0
      printf "0x%x -> %s (at 0x%x, size=%d, offset +0x%x", targets[t], best, best_addr, best_size, targets[t]-best_addr
      if (best_size > 0 && targets[t] < end) printf ", WITHIN function"
      else if (best_size > 0) printf ", OUTSIDE function bounds"
      printf ")\n"
    }
  }
'

